// // This is a 4-bit Lookahead Carry Unit Module
// It calculates carry-out and propagate signals for 4-bit inputs
// The module takes 4-bit inputs p and g, and a single bit input c_in
// Outputs include 3-bit carry signal c, 1-bit carry-out c_out, and 1-bit propagate signal P
// The generate signal G is also calculated based on the inputs
module top_module(c_in, c_out, c, p, g, P, G);input [3:0] p, g;
   input c_in;

   output [2:0] c;
   output c_out;
   output P, G;

   assign  c[0] = g[0] | (p[0] & c_in); 
   assign  c[1] = g[1] | (g[0] & p[1]) | (p[1] & p[0] & c_in); 
   assign  c[2] = g[2] | (g[1] & p[2]) | (g[0] & p[1] & p[2]) | (p[2] & p[1] & p[0] & c_in); 
   assign  c_out = g[3] | (g[2] & p[3]) | (g[1] & p[2] & p[3]) | (g[0] & p[1] & p[2] & p[3]) | (p[3] & p[2] & p[1] & p[0] & c_in);  

   assign  G = g[3] | (g[2] & p[3]) | (g[1] & p[2] & p[3]) | (p[3] & p[2] & p[1] & g[0]);
   assign  P = p[3] & p[2] & p[1] & p[0];

endmodule

